const body=document.body;const root=document.documentElement;const menu=document.querySelector("[data-menu]");const menuToggle=document.querySelector("[data-menu-toggle]");const menuBackdrop=document.querySelector("[data-menu-backdrop]");const themeToggle=document.querySelector("[data-theme-toggle]");const themeLabel=document.querySelector("[data-theme-label]");const navLinks=Array.from(document.querySelectorAll(".site-nav a"));const mobileQuery=window.matchMedia("(max-width: 1100px)");const themeStorageKey="ish-theme";const sections=navLinks.map((link)=>{const href=link.getAttribute("href")||"";if(!href.startsWith("#"))return null;try{return document.querySelector(href);}catch{return null;}}).filter(Boolean);function storedTheme(){try{const value=localStorage.getItem(themeStorageKey);return value==="dark"||value==="light"?value:null;}catch{return null;}}function syncThemeToggle(theme){if(!themeToggle||!themeLabel)return;const nextTheme=theme==="dark"?"light":"dark";const currentLabel=theme==="dark"?"Dark mode active":"Light mode active";const nextLabel=nextTheme==="dark"?"dark mode":"light mode";const label=`${currentLabel}. Switch to ${nextLabel}.`;themeToggle.setAttribute("aria-label",label);themeToggle.setAttribute("aria-pressed",String(theme==="dark"));themeToggle.setAttribute("data-theme-tooltip",label);themeToggle.title=label;themeLabel.textContent=label;}function applyTheme(theme){root.dataset.theme=theme;root.style.colorScheme=theme;syncThemeToggle(theme);}applyTheme(root.dataset.theme==="dark"||root.dataset.theme==="light"?root.dataset.theme:storedTheme()||"light");if(themeToggle){themeToggle.addEventListener("click",()=>{const nextTheme=root.dataset.theme==="dark"?"light":"dark";applyTheme(nextTheme);try{localStorage.setItem(themeStorageKey,nextTheme);}catch{}});}function setMenu(open){menu.classList.toggle("is-open",open);menuToggle.setAttribute("aria-expanded",String(open));menuToggle.setAttribute("aria-label",open?"Close navigation":"Open navigation");body.classList.toggle("menu-open",open);if(menuBackdrop){menuBackdrop.hidden=!open;}syncMenuAccessibility(open);}function syncMenuAccessibility(open=menu.classList.contains("is-open")){const hidden=mobileQuery.matches&&!open;menu.setAttribute("aria-hidden",String(hidden));navLinks.forEach((link)=>{if(hidden){link.setAttribute("tabindex","-1");}else{link.removeAttribute("tabindex");}});}menuToggle.addEventListener("click",()=>{setMenu(!menu.classList.contains("is-open"));});navLinks.forEach((link)=>{link.addEventListener("click",()=>setMenu(false));});if(menuBackdrop){menuBackdrop.addEventListener("click",()=>setMenu(false));}const revealObserver=new IntersectionObserver((entries)=>{entries.forEach((entry)=>{if(entry.isIntersecting){entry.target.classList.add("is-visible");revealObserver.unobserve(entry.target);}});},{threshold:0.12});document.querySelectorAll(".reveal:not(.is-visible)").forEach((element)=>{revealObserver.observe(element);});const navObserver=new IntersectionObserver((entries)=>{entries.forEach((entry)=>{if(!entry.isIntersecting)return;const id=`#${entry.target.id}`;navLinks.forEach((link)=>{link.classList.toggle("active",link.getAttribute("href")===id);});});},{rootMargin:"-35% 0px -55% 0px",threshold:0});sections.forEach((section)=>navObserver.observe(section));const currentPage=body.dataset.page;if(currentPage){navLinks.forEach((link)=>{link.classList.toggle("active",link.dataset.nav===currentPage);});}document.addEventListener("keydown",(event)=>{if(event.key==="Escape"){setMenu(false);}});const committeeFilters=Array.from(document.querySelectorAll("[data-committee-filter]"));const committeeSections=Array.from(document.querySelectorAll("[data-committee-section]"));function setCommitteeFilter(filter){committeeFilters.forEach((button)=>{const active=button.dataset.committeeFilter===filter;button.classList.toggle("is-active",active);button.setAttribute("aria-pressed",String(active));});committeeSections.forEach((section)=>{const visible=filter==="all"||section.dataset.committeeSection===filter;section.classList.toggle("is-hidden",!visible);});}committeeFilters.forEach((button)=>{button.addEventListener("click",()=>setCommitteeFilter(button.dataset.committeeFilter));});if(committeeFilters.length){setCommitteeFilter("all");}mobileQuery.addEventListener("change",()=>{if(!mobileQuery.matches){setMenu(false);}syncMenuAccessibility();});syncMenuAccessibility();const scrollProgress=document.querySelector(".scroll-progress");if(scrollProgress){const updateProgress=()=>{const total=document.documentElement.scrollHeight-window.innerHeight;const pct=total>0?(window.scrollY/total)*100:0;scrollProgress.style.setProperty("--progress",pct+"%");};window.addEventListener("scroll",updateProgress,{passive:true});updateProgress();}const backToTop=document.querySelector(".back-to-top");if(backToTop){window.addEventListener("scroll",()=>{backToTop.classList.toggle("is-visible",window.scrollY>500);},{passive:true});backToTop.addEventListener("click",()=>{window.scrollTo({top:0,behavior:"smooth"});});}function updateCountdown(){const el=document.querySelector("[data-countdown]");if(!el)return;const target=new Date(el.dataset.countdown+"T09:00:00-03:00");const now=new Date();const diff=target-now;const set=(unit,val)=>{const node=el.querySelector(`[data-unit="${unit}"]`);if(node)node.textContent=diff<=0?"0":String(val).padStart(2,"0");};if(diff<=0){set("days",0);set("hours",0);set("minutes",0);return;}set("days",Math.floor(diff/864e5));set("hours",Math.floor((diff%864e5)/36e5));set("minutes",Math.floor((diff%36e5)/6e4));}updateCountdown();setInterval(updateCountdown,30000);
